  1→import { lazy, Suspense } from 'react'
  2→import './App.css'
  3→import { Routes, Route, BrowserRouter, Navigate} from 'react-router-dom'
  4→import { useAuth } from './Context/useAuth.js';
  5→import { LexicalComposer } from '@lexical/react/LexicalComposer';
  6→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  7→import ImageNode from './components/HomePage/Editor/nodes/ImageNode.jsx';
  8→import MentionNode from './components/HomePage/Editor/nodes/MentionNode.jsx';
  9→import Loader from './components/loadingComponent/BgLoader.jsx';
 10→import SeoManager from './seo/SeoManager.jsx';
 11→
 12→const AuthModal = lazy(() => import('./components/AuthModal/AuthModal.jsx'));
 13→const HomePage = lazy(() => import('./components/HomePage/Home.jsx'));
 14→const LoginPage = lazy(() => import('./components/LoginPage/login.jsx'));
 15→const SignUp = lazy(() => import('./components/SignUpPage/signup.jsx'));
 16→const MyProfile = lazy(() => import('./components/ProfilePage/MyProfile.jsx'));
 17→const PostCards = lazy(() => import('./components/HomePage/postCards/PostCards.jsx'));
 18→const ContentView = lazy(() => import('./components/HomePage/ContentViewer/ContentView.jsx'));
 19→const Bookmarks = lazy(() => import('./components/Bookmarks/Bookmarks.jsx'));
 20→const Visitprofile = lazy(() => import('./components/VisitProfile/Visitprofile.jsx'));
 21→const ProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/ProfilePostCards.jsx'));
 22→const ProfileMediaSection = lazy(() => import('./components/ProfilePage/components/ProfileMediaSection.jsx'));
 23→const VisitedProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/VisitedProfilePostCards.jsx'));
 24→const VisitedProfileMediaSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileMediaSection.jsx'));
 25→const Notifications = lazy(() => import('./components/Notifications/Notifications.jsx'));
 26→const NotificationCards = lazy(() => import('./components/Notifications/notificationsCards.jsx'));
 27→const UnreadNotification = lazy(() => import('./components/Notifications/UnreadNotificationCard.jsx'));
 28→const OpinionsPage = lazy(() => import('./components/SidebarOpinions/OpinionssPage.jsx'));
 29→const VisitedProfileOpinions = lazy(() => import('./components/SidebarOpinions/visitedProfileOpinions.jsx'));
 30→const MyOpinions = lazy(() => import('./components/SidebarOpinions/MyOpinions.jsx'));
 31→const OpinionViewer = lazy(() => import('./components/SidebarOpinions/opinionViewer.jsx'));
 32→const ExplorePage = lazy(() => import('./components/HomePage/explore/ExplorePage.jsx'));
 33→const SettingsPage = lazy(() => import('./components/SettingsPage/SettingsPage.jsx'));
 34→const StoryDashboard = lazy(() => import('./components/Stories/StoryDashboard/StoryDashboard.jsx'));
 35→const StoryEditor = lazy(() => import('./components/Stories/StoryEditor/StoryEditor.jsx'));
 36→const StoryChapterManager = lazy(() => import('./components/Stories/StoryChapterManager/StoryChapterManager.jsx'));
 37→const ChapterEditor = lazy(() => import('./components/Stories/ChapterEditor/ChapterEditor.jsx'));
 38→const StoryBrowser = lazy(() => import('./components/Stories/StoryBrowser/StoryBrowser.jsx'));
 39→const StoryLibrary = lazy(() => import('./components/Stories/StoryLibrary/StoryLibrary.jsx'));
 40→const StoryDetail = lazy(() => import('./components/Stories/StoryDetail/StoryDetail.jsx'));
 41→const ChapterReader = lazy(() => import('./components/Stories/ChapterReader/ChapterReader.jsx'));
 42→const ProfileStoriesSection = lazy(() => import('./components/ProfilePage/components/ProfileStoriesSection.jsx'));
 43→const VisitedProfileStoriesSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileStoriesSection.jsx'));
 44→
 45→const AppAuthModal = () => {
 46→  const {showAuthModal, closeAuthModal} = useAuth();
 47→  return <AuthModal isOpen={showAuthModal} onClose={closeAuthModal}/>;
 48→}
 49→
 50→const AppSplash = () => {
 51→  const { loading } = useAuth();
 52→  return <Loader isLoading={loading} />;
 53→}
 54→
 55→const App = () => {
 56→
 57→  const theme = {
 58→    paragraph: 'editor-paragraph',
 59→    heading: {
 60→      h1: 'editor-heading-h1',
 61→      h2: 'editor-heading-h2',
 62→      h3: 'editor-heading-h3',
 63→    },
 64→    quote: 'editor-quote',
 65→    text: {
 66→      bold: 'editor-text-bold',
 67→      italic: 'editor-text-italic',
 68→      underline: 'editor-text-underline',
 69→    }
 70→  }
 71→  
 72→  const initaConfig = {
 73→  namespace: "MyLexicalEditor",
 74→  theme,
 75→  //register nodes
 76→  nodes: [ImageNode, HeadingNode, QuoteNode, MentionNode],
 77→  onError(error){
 78→  throw error;
 79→  },
 80→}
 81→
 82→  return (
 83→    <>
 84→    <LexicalComposer initialConfig={initaConfig}>
 85→      <BrowserRouter>
 86→        <SeoManager />
 87→        <AppSplash />
 88→        <Suspense fallback={null}>
 89→          <AppAuthModal/>
 90→          <Routes>
 91→            <Route path='/' element={<Navigate to='/home' replace/>}/>
 92→            <Route path='/index.html' element={<Navigate to='/home' replace/>}/>
 93→            <Route path='/profile' element={<MyProfile/>}>
 94→              <Route index element={<ProfilePostCards/>} />
 95→              <Route path='media' element={<ProfileMediaSection/>} />
 96→              <Route path='myOpinions' element={<MyOpinions/>}/>
 97→              <Route path='stories' element={<ProfileStoriesSection/>}/>
 98→            </Route>
 99→
100→            <Route path='/visitProfile' element={<Visitprofile/>}>
101→              <Route index element={<VisitedProfilePostCards/>}/>
102→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
103→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
104→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
105→            </Route>
106→
107→            <Route path='/u/:username' element={<Visitprofile/>}>
108→              <Route index element={<VisitedProfilePostCards/>}/>
109→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
110→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
111→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
112→            </Route>
113→
114→            <Route path='/home' element={<HomePage/>}>
115→              <Route index element={<PostCards/>}/>
116→              <Route path='following' element={<PostCards/>}/>
117→              <Route path='for-you' element={<PostCards/>}/>
118→              <Route path='explore' element={<ExplorePage/>}/>
119→              <Route path='contentViewer' element={<ContentView/>}/>
120→              <Route path='post/:journalId' element={<ContentView/>}/>
121→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
122→              <Route path='bookmark' element={<Bookmarks/>}/>
123→              <Route path='opinions'element={<OpinionsPage/>}/>
124→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
125→
126→              <Route path='settings' element={<SettingsPage/>}/>
127→
128→              {/* Stories routes */}
129→              <Route path='stories' element={<StoryBrowser/>}/>
130→              <Route path='stories/library' element={<StoryLibrary/>}/>
131→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
132→              <Route path='stories/new' element={<StoryEditor/>}/>
133→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
134→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
135→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
136→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
137→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
138→
139→              {/* route for nested notifications */}
140→              <Route path='notifications' element={<Notifications/>}>
141→                <Route index element={<NotificationCards/>}/>
142→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
143→              </Route>  
144→            </Route>   
145→
146→            <Route path='/login' element={<LoginPage/>}/>
147→            <Route path='/signUp' element={<SignUp/>}/>
148→          </Routes>
149→        </Suspense>
150→      </BrowserRouter>
151→    </LexicalComposer>
152→    </>
153→  )
154→}
155→
156→export default App
