188→const ExplorePage = () => {
189→    const navigate = useNavigate();
190→    const { session, user, openAuthModal } = useAuth();
191→    const userId = user?.userData?.[0]?.id || null;
192→    const mutateViews = useAddViewsMutation(session);
193→    const searchShellRef = useRef(null);
194→
195→    const [searchInput, setSearchInput] = useState("");
196→    const [debouncedSearchInput, setDebouncedSearchInput] = useState("");
197→    const [committedSearchQuery, setCommittedSearchQuery] = useState("");
198→    const [isSearchFocused, setIsSearchFocused] = useState(false);
199→    const [searchType, setSearchType] = useState("posts");
200→    const onClickProfile = handleClickProfile(navigate);
201→    const currentUtcMonthKey = `${new Date().getUTCFullYear()}-${String(new Date().getUTCMonth() + 1).padStart(2, "0")}`;
202→
203→    useEffect(() => {
204→        const timer = setTimeout(() => {
205→            setDebouncedSearchInput(searchInput.trim());
206→        }, 350);
207→
208→        return () => clearTimeout(timer);
209→    }, [searchInput]);
210→
211→    const isSearchMode = committedSearchQuery.length >= 2;
212→
213→    const { data: feedData, isLoading: isLoadingFeed } = useQuery({
214→        queryKey: ["explore-hottest-monthly-feed", userId, currentUtcMonthKey],
215→        queryFn: () => getMonthlyHottestJournals(userId, 10),
216→        refetchOnWindowFocus: false,
217→        staleTime: 1000 * 60 * 5,
218→    });
219→
220→    const { data: interestData } = useQuery({
221→        queryKey: ["explore-interest-sections", session?.access_token],
222→        queryFn: () => getInterestSections(session?.access_token),
223→        refetchOnWindowFocus: false,
224→        staleTime: 1000 * 60 * 10,
225→        enabled: !!session?.access_token && !isSearchMode,
226→    });
227→
228→    const {
229→        data: searchData,
230→        isLoading: isLoadingSearch,
231→        isFetching: isFetchingSearch,
232→        error: searchError,
233→    } = useQuery({
234→        queryKey: ["explore-search", userId, committedSearchQuery],
235→        queryFn: () => searchJournals(committedSearchQuery, 10, userId),
236→        enabled: isSearchMode,
237→        refetchOnWindowFocus: false,
238→        staleTime: 1000 * 60 * 2,
239→    });
240→
241→    const {
242→        data: suggestionData,
243→        isLoading: isSuggestionsLoading,
244→    } = useQuery({
245→        queryKey: ["explore-suggestions", userId, debouncedSearchInput],
246→        queryFn: () => searchJournals(debouncedSearchInput, 6, userId),
247→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused && searchType === "posts",
248→        refetchOnWindowFocus: false,
249→        staleTime: 1000 * 60 * 2,
250→    });
251→
252→    const {
253→        data: userSuggestionData,
254→        isLoading: isUserSuggestionsLoading,
255→    } = useQuery({
256→        queryKey: ["user-suggestions", debouncedSearchInput],
257→        queryFn: () => searchUsers(debouncedSearchInput, 6),
258→        enabled: debouncedSearchInput.length >= 2 && isSearchFocused && searchType === "people",
259→        refetchOnWindowFocus: false,
260→        staleTime: 1000 * 60 * 2,
261→    });
262→
263→    const journals = isSearchMode ? (searchData?.data || []) : (feedData?.data || []);
264→    const isLoading = isSearchMode && searchType === "posts" ? isLoadingSearch : isLoadingFeed;
265→    const suggestionItems = searchType === "people" ? (userSuggestionData?.data || []) : (suggestionData?.data || []);
266→    const isSugLoading = searchType === "people" ? isUserSuggestionsLoading : isSuggestionsLoading;
267→    const showSuggestions = isSearchFocused && debouncedSearchInput.length >= 2;
268→
269→    const handleSubmitSearch = (rawQuery) => {
270→        const normalizedQuery = typeof rawQuery === "string" ? rawQuery.trim() : "";
271→        if(normalizedQuery.length < 2){
272→            setCommittedSearchQuery("");
273→            return;
274→        }
275→
276→        setCommittedSearchQuery(normalizedQuery);
277→        setSearchInput(normalizedQuery);
278→        setIsSearchFocused(false);
279→    };
280→
281→    const handleClearSearch = () => {
282→        setSearchInput("");
283→        setDebouncedSearchInput("");
284→        setCommittedSearchQuery("");
285→        setIsSearchFocused(false);
286→        setSearchType("posts");
287→    };
288→
289→    const handleSearchInputKeyDown = (e) => {
290→        if(e.key === "Enter"){
291→            e.preventDefault();
292→            handleSubmitSearch(searchInput);
293→        }
294→
295→        if(e.key === "Escape"){
296→            setIsSearchFocused(false);
297→        }
298→    };
299→
300→    const handleClickSuggestion = (journal) => {
301→        if(!journal?.id){
302→            return;
303→        }
