358→                <div className="search-top-bar">
359→                    <div className="search-input-wrap">
360→                        <svg className="search-icon" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" aria-hidden="true">
361→                            <path d="M10 2a8 8 0 1 0 4.906 14.32l4.387 4.387a1 1 0 0 0 1.414-1.414L16.32 14.906A8 8 0 0 0 10 2Zm0 2a6 6 0 1 1 0 12a6 6 0 0 1 0-12Z"/>
362→                        </svg>
363→                        <input
364→                            type="search"
365→                            value={searchInput}
366→                            onChange={(e) => setSearchInput(e.target.value)}
367→                            onFocus={() => setIsSearchFocused(true)}
368→                            onKeyDown={handleSearchInputKeyDown}
369→                            placeholder={searchType === "people" ? "Search people..." : "Search posts..."}
370→                            className="search-input"
371→                            aria-label={searchType === "people" ? "Search people" : "Search posts"}
372→                        />
373→                    </div>
374→                    {searchInput ? (
