 10→
 11→const incrementJournalCommentCount = (old, postId) => {
 12→    if (!old || !Array.isArray(old.pages)) return old;
 13→
 14→    return {
 15→        ...old,
 16→        pages: old.pages.map((page) => ({
 17→            ...page,
 18→            data: Array.isArray(page?.data)
 19→                ? page.data.map((journal) => {
 20→                    if (journal?.id !== postId) return journal;
 21→
 22→                    const currentCount = journal?.comment_count?.[0]?.count ?? 0;
 23→                    return {
 24→                        ...journal,
 25→                        comment_count: [{ count: currentCount + 1 }],
 26→                    };
 27→                })
 28→                : page?.data,
 29→        })),
 30→    };
 31→};
 32→
 33→const CommentSection = ({onclose, postId, receiverId})=>{
 34→    const queryClient = useQueryClient();
 35→
 36→    const {session, user} = useAuth();
 37→
 38→    const textAreaFocusRef = useRef();
 39→
 40→    const [comments, setComments] = useState('');
 41→    const [isSubmittingComment, setIsSubmittingComment] = useState(false);
 42→
 43→    const {data, fetchNextPage, hasNextPage, isLoading, isFetchingNextPage} = useInfiniteQuery({
 44→        queryKey: ['postComments', postId],
 45→        queryFn: ({queryKey, pageParam = null}) => getComments(pageParam, 10, queryKey[1]),
 46→        getNextPageParam: (lastPage) => {
 47→            if(lastPage?.hasMore) {
 48→                const lastComment = lastPage.comments[lastPage?.comments?.length - 1];
 49→                return new Date(lastComment.created_at).toISOString();
 50→            } else {
 51→                return undefined;
 52→            }
 53→        },
 54→        refetchOnWindowFocus: false,
 55→        staleTime: 1000 * 60 * 5
 56→    })
 57→
 58→    const handleSeeMoreComments = (e) =>{
 59→        e.stopPropagation();
 60→        if(hasNextPage && !isFetchingNextPage){
 61→            try {
 62→                fetchNextPage()
 63→            } catch (error) {
 64→                throw new Error(error);
 65→            }
 66→        }
 67→    }
 68→
 69→    useEffect(() =>{
 70→        let timeout;
 71→        if(textAreaFocusRef.current){
 72→            timeout = setTimeout(() => {
 73→                textAreaFocusRef.current.focus();
 74→            }, 500);
 75→        }
 76→        return () => {
 77→             clearTimeout(timeout);
 78→        }
 79→    }, [])
 80→
 81→    const handeCloseCommentsSection = (e) =>{
 82→        e.stopPropagation();
 83→        onclose()
 84→    }
 85→
 86→    const handaleSubmitComment = async(e, postId, receiverId) =>{
 87→        e.stopPropagation();
 88→        const trimmedComment = comments.trim();
 89→        if (!trimmedComment) return;
 90→
 91→        const optimisticComment = {
 92→            id: `optimistic-${Date.now()}`,
 93→            comment: trimmedComment,
 94→            created_at: new Date().toISOString(),
 95→            parent_id: null,
 96→            post_id: postId,
 97→            reply_count: 0,
 98→            user_id: user?.userData?.[0]?.id,
 99→            users: {
100→                id: user?.userData?.[0]?.id,
101→                name: user?.userData?.[0]?.name,
102→                image_url: user?.userData?.[0]?.image_url,
103→                badge: user?.userData?.[0]?.badge,
104→            },
105→        };
106→
107→        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
108→        const previousComments = queryClient.getQueryData(['postComments', postId]);
109→        const previousJournalCaches = [
110→            ...queryClient.getQueriesData({ queryKey: ['journals'] }),
111→            ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
112→            ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
113→        ];
114→
115→        queryClient.setQueryData(['postComments', postId], (old) => {
116→            if (!old || !Array.isArray(old.pages)) {
117→                return {
118→                    pageParams: [null],
119→                    pages: [{ comments: [optimisticComment], hasMore: false }],
120→                };
121→            }
122→
123→            return {
124→                ...old,
125→                pages: old.pages.map((page, index) =>
126→                    index === 0
127→                        ? { ...page, comments: [optimisticComment, ...(page?.comments || [])] }
128→                        : page
129→                ),
130→            };
131→        });
132→
133→        queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => incrementJournalCommentCount(old, postId));
134→        queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => incrementJournalCommentCount(old, postId));
135→        queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => incrementJournalCommentCount(old, postId));
136→
137→        const body = {
138→            comments: trimmedComment,
139→            postId: postId,
140→            receiverId: receiverId,
141→        }
142→
143→        try {
144→            setIsSubmittingComment(true)
145→            const message = await addComment(session?.access_token, body);
146→            if(message){
147→                // console.log(message)
148→            }
149→            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
150→            queryClient.invalidateQueries({ queryKey: ['journals'] });
151→            queryClient.invalidateQueries({ queryKey: ['userJournals'] });
152→            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
153→        } catch (error) {
154→            queryClient.setQueryData(['postComments', postId], previousComments);
155→            previousJournalCaches.forEach(([key, value]) => {
156→                queryClient.setQueryData(key, value);
157→            });
158→            throw new Error('error adding comments')
159→        } finally {
160→            setIsSubmittingComment(false)
161→            setComments('')
162→        }
163→    }
164→
165→    const commentsData = data?.pages?.flatMap((page) => page.comments || []);
166→
167→    return(
168→        <motion.div
169→            initial={{y: '100vh', opacity: 0}}
170→            animate={{
171→                y: 0,
172→                opacity: 1,
173→                transition: {type: 'spring', damping: 25, stiffness: 200}
174→            }}
175→            exit={{y: '-100vh', opacity: 0, transition: {duration: 0.2}}}
176→            className="cm-parent-container"
177→        >
178→            <div className="cm-header">
179→                <p className="cm-header-title">Comments</p>
180→                <div className="cm-close-btn" onClick={(e) => handeCloseCommentsSection(e)}>
181→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px">
182→                        <path d="m336-280-56-56 144-144-144-143 56-56 144 144 143-144 56 56-144 143 144 144-56 56-143-144-144 144Z"/>
183→                    </svg>
184→                </div>
185→            </div>
186→
187→            <div className="cm-list">
188→                {isLoading ? (
189→                    <div className="cm-loading">
190→                        <MoonLoader color='rgba(19, 77, 104, 1)' size={20} loading={isLoading}/>
191→                    </div>
192→                ) : (
193→                    commentsData?.map((comment, index) => (
194→                        <CommentsCards postId={postId} key={comment?.id || index} comments={comment}/>
195→                    ))
196→                )}
197→
198→                {hasNextPage && (
199→                    <button onClick={(e) => handleSeeMoreComments(e)} className="cm-load-more">
200→                        See more comments
201→                        {isFetchingNextPage && (<MoonLoader size={12} speedMultiplier={0.5} color='rgba(19, 77, 104, 1)'/>)}
202→                    </button>
203→                )}
204→            </div>
205→
206→            <div className="cm-input-area">
207→                <div className="cm-input-row">
208→                    <textarea
209→                        ref={textAreaFocusRef}
210→                        value={comments}
211→                        onChange={(e) => setComments(e.target.value)}
212→                        className="cm-textarea"
213→                        maxLength={200}
214→                        placeholder="Write a comment..."
215→                        rows={1}
216→                    />
217→                    <button
218→                        disabled={isSubmittingComment || !comments.trim()}
219→                        onClick={(e) => handaleSubmitComment(e, postId, receiverId)}
220→                        className="cm-submit-btn"
221→                    >
222→                        Submit
223→                    </button>
224→                </div>
225→                <div className="cm-action-row">
226→                    <p className={`cm-char-count ${comments.length > 199 ? 'cm-char-limit' : ''}`}>
227→                        {comments.length}/200
228→                    </p>
229→                </div>
230→            </div>
231→
232→            {isSubmittingComment && (
233→                <div className="cm-progress">
234→                    <BarLoader loading={isSubmittingComment} width={'100%'} color="rgb(40, 115, 255)" speedMultiplier={0.9}/>
235→                </div>
236→            )}
237→        </motion.div>
238→    )
239→}
240→
241→export default CommentSection;
